# ==================== ВСПОМОГАТЕЛЬНЫЕ ФУНКЦИИ ====================

def get_problem_by_code(category: str, subcategory: str, problem_code: str) -> dict:
    """Get problem details by its code"""
    problems = PROBLEMS.get(category, {}).get(subcategory, [])
    for problem in problems:
        if problem["code"] == problem_code:
            return problem
    return None